// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements.

import bcrypt from "bcryptjs";
import Database from "better-sqlite3";
import express, { type Request, type RequestHandler } from "express";
import jwt from "jsonwebtoken";

const app = express();
const PORT = Number(process.env.PORT ?? 3000);
const JWT_SECRET = "benchmark-secret";
const db = new Database(process.env.DATA_DB ?? "data.db");

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = Omit<User, "password_hash">;

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  user_id: number;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  user_id: number;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

declare global {
  namespace Express {
    interface Request {
      userId?: number;
    }
  }
}

type JwtPayloadWithUser = jwt.JwtPayload & {
  userId?: unknown;
};

db.pragma("foreign_keys = ON");
db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const ensureColumn = (table: string, column: string, definition: string): void => {
  const columns = db.prepare(`PRAGMA table_info(${table})`).all() as Array<{ name: string }>;
  if (!columns.some((existingColumn) => existingColumn.name === column)) {
    db.prepare(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`).run();
  }
};

ensureColumn("bookmarks", "folder_id", "INTEGER REFERENCES folders(id) ON DELETE SET NULL");
ensureColumn("bookmarks", "user_id", "INTEGER REFERENCES users(id) ON DELETE CASCADE");
ensureColumn("folders", "user_id", "INTEGER REFERENCES users(id) ON DELETE CASCADE");

app.use(express.json());

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const isValidEmail = (value: unknown): value is string =>
  typeof value === "string" && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

const isValidPassword = (value: unknown): value is string =>
  typeof value === "string" && value.length >= 8;

const getUserByEmail = (email: string): User | undefined =>
  db
    .prepare("SELECT id, email, password_hash, created_at FROM users WHERE email = ?")
    .get(email) as User | undefined;

const getPublicUserById = (id: number): PublicUser | undefined =>
  db
    .prepare("SELECT id, email, created_at FROM users WHERE id = ?")
    .get(id) as PublicUser | undefined;

const getBookmarkById = (id: number, userId: number): Bookmark | undefined =>
  db
    .prepare(
      `SELECT id, url, title, description, folder_id, user_id, created_at, updated_at
       FROM bookmarks
       WHERE id = ? AND user_id = ?`
    )
    .get(id, userId) as Bookmark | undefined;

const getFolderById = (id: number, userId: number): Folder | undefined =>
  db
    .prepare(
      "SELECT id, name, user_id, created_at, updated_at FROM folders WHERE id = ? AND user_id = ?"
    )
    .get(id, userId) as Folder | undefined;

const parsePositiveInteger = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseFolderIdInput = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  return typeof value === "number" && Number.isInteger(value) && value > 0 ? value : undefined;
};

const isValidFolderReference = (
  folderId: number | null | undefined,
  userId: number
): boolean => folderId === undefined || folderId === null || Boolean(getFolderById(folderId, userId));

const getAuthenticatedUserId = (req: Request): number => {
  if (typeof req.userId !== "number") {
    throw new Error("Authenticated route reached without user context");
  }

  return req.userId;
};

const authenticate: RequestHandler = (req, res, next) => {
  const authorization = req.header("authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    return res.status(401).json({ error: "authentication required" });
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET) as JwtPayloadWithUser;
    if (typeof payload.userId !== "number" || !getPublicUserById(payload.userId)) {
      return res.status(401).json({ error: "invalid token" });
    }

    req.userId = payload.userId;
    return next();
  } catch {
    return res.status(401).json({ error: "invalid token" });
  }
};

app.post("/auth/register", async (req, res) => {
  const { email, password } = req.body ?? {};

  if (!isValidEmail(email)) {
    return res.status(400).json({ error: "email must be valid" });
  }

  if (!isValidPassword(password)) {
    return res.status(400).json({ error: "password must be at least 8 characters" });
  }

  const normalizedEmail = email.trim().toLowerCase();
  if (getUserByEmail(normalizedEmail)) {
    return res.status(409).json({ error: "email already exists" });
  }

  const now = new Date().toISOString();
  const passwordHash = await bcrypt.hash(password, 10);
  const result = db
    .prepare("INSERT INTO users (email, password_hash, created_at) VALUES (?, ?, ?)")
    .run(normalizedEmail, passwordHash, now);

  const user = getPublicUserById(Number(result.lastInsertRowid));
  return res.status(201).json(user);
});

app.post("/auth/login", async (req, res) => {
  const { email, password } = req.body ?? {};

  if (!isValidEmail(email)) {
    return res.status(400).json({ error: "email must be valid" });
  }

  if (!isNonEmptyString(password)) {
    return res.status(400).json({ error: "password is required" });
  }

  const user = getUserByEmail(email.trim().toLowerCase());
  if (!user || !(await bcrypt.compare(password, user.password_hash))) {
    return res.status(401).json({ error: "invalid credentials" });
  }

  return res.status(200).json({ token: jwt.sign({ userId: user.id }, JWT_SECRET) });
});

app.use("/bookmarks", authenticate);
app.use("/folders", authenticate);

app.post("/bookmarks", (req, res) => {
  const userId = getAuthenticatedUserId(req);
  const { url, title, description, folder_id } = req.body ?? {};

  if (!isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  if (!isNonEmptyString(title)) {
