app.get("/bookmarks/:id", (req, res) => {
  const userId = getAuthenticatedUserId(req);
  const id = parsePositiveInteger(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = getBookmarkById(id, userId);

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const userId = getAuthenticatedUserId(req);
  const id = parsePositiveInteger(req.params.id);
  const existingBookmark = id === null ? undefined : getBookmarkById(id, userId);

  if (id === null || !existingBookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const { url, title, description, folder_id } = req.body ?? {};

  if (url !== undefined && !isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  if (url !== undefined) {
    try {
      new URL(url.trim());
    } catch {
      return res.status(400).json({ error: "url must be valid" });
    }
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be a non-empty string" });
  }

  const parsedFolderId = parseFolderIdInput(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must reference an existing folder" });
  }

  if (!isValidFolderReference(parsedFolderId, userId)) {
    return res.status(400).json({ error: "folder_id must reference an existing folder" });
  }

  const now = new Date().toISOString();
  db.prepare(
    `UPDATE bookmarks
     SET url = COALESCE(?, url),
         title = COALESCE(?, title),
         description = ?,
         folder_id = ?,
         updated_at = ?
     WHERE id = ? AND user_id = ?`
  ).run(
    typeof url === "string" ? url.trim() : null,
    typeof title === "string" ? title.trim() : null,
    description === undefined
      ? existingBookmark.description
      : typeof description === "string"
        ? description
        : null,
    folder_id === undefined ? existingBookmark.folder_id : parsedFolderId,
    now,
    id,
    userId
  );

  return res.status(200).json(getBookmarkById(id, userId));
});

app.delete("/bookmarks/:id", (req, res) => {
  const userId = getAuthenticatedUserId(req);
  const id = parsePositiveInteger(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = db.prepare("DELETE FROM bookmarks WHERE id = ? AND user_id = ?").run(id, userId);

  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

